export default function Navbar({ setPage, user, onLogout, onBack, showBack, search, setSearch }) {
  return (
    <nav className="top-nav" style={{ 
      background: "rgba(255, 255, 255, 0.8)", 
      backdropFilter: "blur(12px)",
      borderBottom: "1px solid var(--border-light)",
      display: "flex", 
      alignItems: "center", 
      justifyContent: "space-between", 
      padding: "0 24px", 
      height: "68px", 
      position: "sticky", 
      top: 0, 
      zIndex: 1000 
    }}>
      {/* Left: Logo & Back */}
      <div style={{ display: "flex", alignItems: "center", gap: "16px", minWidth: "150px" }}>
        {showBack && (
          <button className="btn-back" onClick={onBack} style={{ padding: "6px 10px" }}>
            <span style={{ fontSize: "16px" }}>←</span>
          </button>
        )}
        <button 
          className="top-nav-logo" 
          onClick={() => setPage("home")}
          style={{ background: "none", border: "none", display: "flex", alignItems: "center", gap: "8px", color: "var(--navy)", fontSize: "19px", fontWeight: "800", fontFamily: "'Playfair Display', serif" }}
        >
          <div style={{ width: "28px", height: "28px", background: "var(--primary)", borderRadius: "7px", display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontSize: "15px" }}>🍽</div>
          RecipeNest
        </button>
      </div>

      {/* Center Group: Links & Search */}
      <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", gap: "30px" }}>
        <div className="top-nav-links" style={{ display: "flex", gap: "20px" }}>
          <button className="top-nav-link" onClick={() => setPage("home")} style={{ fontSize: "14px", fontWeight: "600" }}>Discover</button>
          <button className="top-nav-link" style={{ fontSize: "14px", fontWeight: "600" }}>About</button>
          <button className="top-nav-link" style={{ fontSize: "14px", fontWeight: "600" }}>Contact</button>
          <button className="top-nav-link" style={{ fontSize: "14px", fontWeight: "600" }}>Community</button>
        </div>

        <div style={{ flex: 1, maxWidth: "320px", position: "relative" }}>
          <div style={{ 
            background: "#f1f5f9",
            borderRadius: "10px",
            display: "flex",
            alignItems: "center",
            padding: "6px 14px",
            border: "1px solid #e2e8f0"
          }}>
            <span style={{ fontSize: "13px", marginRight: "8px", opacity: 0.5 }}>🔍</span>
            <input 
              type="text"
              placeholder="Search..."
              value={search}
              onChange={(e) => {
                setSearch(e.target.value);
                setPage("home");
              }}
              style={{ 
                background: "none",
                border: "none",
                outline: "none",
                fontSize: "13px",
                width: "100%",
                color: "var(--navy)"
              }}
            />
          </div>
        </div>
      </div>

      {/* Right: Actions */}
      <div style={{ display: "flex", alignItems: "center", gap: "12px", minWidth: "150px", justifyContent: "flex-end" }}>
        {user ? (
          <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
            <button 
              onClick={() => {
                if (user.role === "user") setPage("user-dashboard");
                else if (user.role === "chef") setPage("chef-dashboard");
                else if (user.role === "admin") setPage("admin-dashboard");
              }}
              style={{ 
                background: "none", 
                border: "none", 
                display: "flex", 
                alignItems: "center", 
                gap: "8px",
                padding: "4px 8px",
                borderRadius: "10px"
              }}
            >
              <div style={{ width: "32px", height: "32px", borderRadius: "50%", background: "var(--primary)", color: "#fff", fontSize: "12px", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: "700" }}>
                {user.name[0]}
              </div>
              <span style={{ fontSize: "14px", fontWeight: "600", color: "var(--navy)" }}>{user.name.split(' ')[0]}</span>
            </button>
          </div>
        ) : (
          <>
            <button className="top-nav-link" onClick={() => setPage("login")} style={{ fontWeight: "600", fontSize: "14px" }}>Sign In</button>
            <button className="btn-primary" style={{ padding: "8px 18px", fontSize: "13px" }} onClick={() => setPage("signup")}>Sign Up</button>
          </>
        )}
      </div>
    </nav>
  );
}
